  function loadData() {
    try {
      const current = typeof state !== "undefined" ? state : null;
      if (current && Array.isArray(current.customers)) return current;
      return JSON.parse(localStorage.getItem(STORAGE) || "{}");
    } catch (error) {
      return {};
    }
  }

  function saveData(data) {
    if (typeof state !== "undefined" && state && Array.isArray(state.customers)) {
      state.customers = data.customers;
      if (typeof saveState === "function") saveState();
      else localStorage.setItem(STORAGE, JSON.stringify(data));
      return;
    }
    localStorage.setItem(STORAGE, JSON.stringify(data));
  }

  function runImport() {
    if (typeof localStorage === "undefined") return;
    const data = loadData();
    if (!data || !Array.isArray(data.customers)) return;
    const existingIds = new Set(data.customers.map((item) => item.id));
    const incoming = CUSTOMERS.filter((item) => !existingIds.has(item.id));
    if (!incoming.length) {
      localStorage.setItem(MARKER, "already-present");
      window.__localUnreviewedBatchImport = { imported: 0, skipped: CUSTOMERS.length };
      return;
    }
    const stamp = new Date().toISOString();
    const rows = incoming.map((item) => ({ ...item, created_at: stamp }));
    data.customers.unshift(...rows);
    saveData(data);
    localStorage.setItem(MARKER, stamp);
    window.__localUnreviewedBatchImport = { imported: rows.length, skipped: CUSTOMERS.length - rows.length, marker: MARKER };
    if (typeof ui !== "undefined" && ui) ui.toast = `??? ${rows.length} ????????`;
    if (!location.hash || !location.hash.startsWith("#/customers")) location.hash = "#/customers";
  }

  runImport();
